const SUB_KEYS = Object.keys(PLANT).sort((a, b) => {
  const [a1, a2] = a.split(".").map(Number);
  const [b1, b2] = b.split(".").map(Number);
  return a1 - b1 || a2 - b2;
});

const LAYERS = [
  { key: "lavagem", label: "Lavagem", icon: "💧",
    states: ["🔴 NÃO LAVADO", "⚫ PENDENTE 22 MÓDULOS", "🔵 PENDENTE 8 MÓDULOS", "🟡 LAVADO PARCIAL 50%", "✅ LAVADO 100%"],
    doneIdx: 4, progIdxes: [2, 3] },
  { key: "rocagem", label: "Roçagem", icon: "🌾",
    states: ["Pendente", "Incompleto", "Concluída"],
    doneIdx: 2, progIdxes: [1] },
  { key: "trator", label: "Acesso trator", icon: "🚜",
    states: ["Não avaliado", "Bloqueado", "Liberado"],
    doneIdx: 2, progIdxes: [1] },
];
const LAYER_IDX = { lavagem: 0, rocagem: 1, trator: 2 };
const LAYER_DONE_IDX = Object.fromEntries(LAYERS.map((l) => [l.key, l.doneIdx]));

const P = {
  bg: "#0d0f14", surface: "#13161d", card: "#181c25", card2: "#1d222d", border: "#252b38",
  accent: "#00e5a0", accentD: "#00b87d", accentG: "rgba(0,229,160,0.13)",
  text: "#e8ecf4", muted: "#6b7691", danger: "#ff5f7e", warn: "#ffb347",
  info: "#4da6ff", purple: "#c084fc",
};

const STATE_COLORS = {
  lavagem: [P.danger, "#475569", P.info, P.warn, P.accent],
  rocagem: [P.border, P.warn, P.accent],
  trator: [P.border, P.danger, P.accent],
};

const GROUP_PALETTE = ["#4da6ff", "#c084fc", "#ffb347", "#00e5a0", "#ff5f7e", "#7dd3fc", "#fb923c", "#a3e635", "#f472b6", "#94a3b8"];

function pad3(n) { return String(n).padStart(3, "0"); }
function trackerId(key, n) {
  const [a, b] = key.split(".");
  return `EC-${a}-${b}-TR-${pad3(n)}`;
}
function median(arr) {
  if (!arr.length) return null;
  const s = [...arr].sort((a, b) => a - b);
  return s[Math.floor(s.length / 2)];
}

/* ── geometria por subcampo: bbox, pitch (espaçamento), grupos ─────────── */
function useSubGeometry(key) {
  return useMemo(() => {
    const { t: trackers, cmd } = PLANT[key];
    let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
    for (const [, x, y] of trackers) {
      if (x < minX) minX = x; if (x > maxX) maxX = x;
      if (y < minY) minY = y; if (y > maxY) maxY = y;
    }
    const byY = {};
    trackers.forEach(([, x, y]) => { (byY[y] = byY[y] || []).push(x); });
    const colDiffs = [];
    Object.values(byY).forEach((xs) => {
      xs.sort((a, b) => a - b);
      for (let i = 1; i < xs.length; i++) colDiffs.push(xs[i] - xs[i - 1]);
    });
    const ys = Object.keys(byY).map(Number).sort((a, b) => a - b);
    const rowDiffs = [];
    for (let i = 1; i < ys.length; i++) rowDiffs.push(ys[i] - ys[i - 1]);
    const col = median(colDiffs) || 11;
    const row = median(rowDiffs) || 70;

    const byG = {};
    trackers.forEach((tr) => { (byG[tr[3]] = byG[tr[3]] || []).push(tr); });
    const groups = Object.entries(byG).map(([g, arr]) => {
      const xs = arr.map((a) => a[1]), ys2 = arr.map((a) => a[2]);
      return {
        g, trackers: arr,
        minX: Math.min(...xs), maxX: Math.max(...xs),
        minY: Math.min(...ys2), maxY: Math.max(...ys2),
      };
    }).sort((a, b) => (Number(a.g) || 0) - (Number(b.g) || 0));

    const pad = Math.max(col, row * 0.18);
    const padTop = Math.max(col, row * 0.55);
    return {
      trackers, cmd, minX, maxX, minY, maxY,
      W: maxX - minX + pad * 2, H: maxY - minY + pad + padTop, pad, padTop,
      col, row, groups,
    };
  }, [key]);
}

/* ── status helpers ──────────────────────────────────────────────────── */
function getStatus(statuses, subKey, n) {
  return (statuses[subKey] && statuses[subKey][n]) || [0, 0, 0];
}
function countDone(statuses, subKey, trackers, layerKey) {
  const idx = LAYER_IDX[layerKey];
  const layer = LAYERS.find((l) => l.key === layerKey);
  let done = 0, prog = 0;
  trackers.forEach(([n]) => {
    const s = getStatus(statuses, subKey, n)[idx];
    if (s === layer.doneIdx) done++;
    else if (layer.progIdxes.includes(s)) prog++;
  });
  return { done, prog, total: trackers.length, pending: trackers.length - done - prog };
}

/* ════════════════════════════════════════════════════════════════════════
   COMPONENTES PEQUENOS
   ════════════════════════════════════════════════════════════════════════ */
function SyncBadge({ state }) {
  const color = { loading: P.muted, ok: P.accent, saving: P.info, error: P.danger, offline: P.warn }[state] || P.muted;
  return (
    <div title={{ loading: "Conectando...", ok: "Sincronizado", saving: "Salvando...", error: "Erro ao sincronizar", offline: "Sem Supabase" }[state]}
      style={{
        width: 8, height: 8, borderRadius: "50%", background: color, flexShrink: 0,
        animation: state === "saving" || state === "loading" ? "pulse 1s ease-in-out infinite" : "none",
      }} />
  );
}

function ProgressBar({ done, prog, total, color }) {
  const pctDone = total ? (done / total) * 100 : 0;
  const pctProg = total ? (prog / total) * 100 : 0;
  return (
    <div style={{ background: P.border, borderRadius: 4, height: 7, overflow: "hidden", display: "flex" }}>
      <div style={{ height: "100%", width: `${pctDone}%`, background: color, transition: "width .3s" }} />
      <div style={{ height: "100%", width: `${pctProg}%`, background: P.warn, transition: "width .3s" }} />
    </div>
  );
}

function LayerTabs({ active, onChange }) {
  return (
    <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
      {LAYERS.map((l) => (
        <button key={l.key} onClick={() => onChange(l.key)} style={{
          display: "flex", alignItems: "center", gap: 6, padding: "8px 14px",
          borderRadius: 8, cursor: "pointer", fontFamily: "inherit", fontSize: 13, fontWeight: 600,
          border: `1px solid ${active === l.key ? P.accent : P.border}`,
          background: active === l.key ? P.accentG : P.card,
          color: active === l.key ? P.accent : P.muted, transition: "all .15s",
        }}>
          <span>{l.icon}</span>{l.label}
        </button>
      ))}
    </div>
  );
}

function FilterChips({ activeLayer, filter, onChange }) {
  const layer = LAYERS.find((l) => l.key === activeLayer);
  const opts = [{ v: null, label: "Todos" }, { v: 0, label: layer.states[0] }, { v: 1, label: layer.states[1] }, { v: 2, label: layer.states[2] }];
  return (
    <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
      {opts.map((o) => (
        <button key={String(o.v)} onClick={() => onChange(filter === o.v ? null : o.v)} style={{
          padding: "5px 11px", borderRadius: 20, fontSize: 11.5, fontFamily: "inherit", cursor: "pointer",
          border: `1px solid ${filter === o.v ? P.info : P.border}`,
          background: filter === o.v ? P.info + "22" : "transparent",
          color: filter === o.v ? P.info : P.muted, fontWeight: 600,
        }}>{o.label}</button>
      ))}
    </div>
  );
}

function Legend({ activeLayer }) {
  const layer = LAYERS.find((l) => l.key === activeLayer);
  const colors = STATE_COLORS[activeLayer];
  return (
    <div style={{ display: "flex", gap: 14, flexWrap: "wrap", fontSize: 11.5, color: P.muted }}>
      {layer.states.map((s, i) => (
        <div key={s} style={{ display: "flex", alignItems: "center", gap: 6 }}>
          <div style={{ width: 12, height: 12, borderRadius: 3, background: colors[i], border: `1px solid ${P.border}` }} />
          {s}
        </div>
      ))}
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════════════
   MAPA SVG DE UM SUBCAMPO
   ════════════════════════════════════════════════════════════════════════ */
function SubMap({ geo, subKey, statuses, activeLayer, filter, showGroups, selected, multiSelected, dragRect, onSvgMouseDown, onClick, scale }) {
  const { trackers, minX, maxY, W, H, pad, padTop, col, row, groups } = geo;
  const markerW = col * 0.82, markerH = row * 0.5;
  const idx = LAYER_IDX[activeLayer];
  const toX = (x) => x - minX + pad;
  const toY = (y) => maxY - y + padTop;
  const multiSet = useMemo(() => new Set(multiSelected), [multiSelected]);

  const vW = W / scale, vH = H / scale;
  const vX = (W - vW) / 2, vY = (H - vH) / 2;
  const sw = Math.max(W, H);
  return (
    <svg width="100%" height="100%" viewBox={`${vX} ${vY} ${vW} ${vH}`} preserveAspectRatio="xMidYMid meet"
      style={{ display: "block", userSelect: "none" }} onMouseDown={onSvgMouseDown}>
      {showGroups && groups.map((g) => {
        const gx = toX(g.minX) - markerW * 0.65, gy = toY(g.maxY) - markerH * 0.75;
        const gw = (g.maxX - g.minX) + markerW * 1.3, gh = (g.maxY - g.minY) + markerH * 1.5;
        const stat = countDone(statuses, subKey, g.trackers, activeLayer);
        const complete = stat.done === stat.total;
        return (
          <g key={g.g}>
            <rect x={gx} y={gy} width={gw} height={gh} fill="none"
              stroke={complete ? P.accent : P.border} strokeOpacity={complete ? 0.7 : 0.55}
              strokeDasharray="4 3" strokeWidth={sw * 0.0014} rx={row * 0.06} />
            <text x={gx + 2} y={gy - row * 0.06} fontSize={row * 0.13} fill={complete ? P.accent : P.muted} fontFamily="monospace">
              G{g.g} {stat.done}/{stat.total}
            </text>
          </g>
        );
      })}

      {trackers.map(([n, x, y, g]) => {
        const st = getStatus(statuses, subKey, n);
        const val = st[idx];
        const color = STATE_COLORS[activeLayer][val];
        const dim = filter !== null && val !== filter;
        const isSel = selected === n;
        const isMulti = multiSet.has(n);
        const cx = toX(x), cy = toY(y);
        const railW = markerW * 0.32;
        const hubH = markerH * 0.13;
        const left = cx - markerW / 2, top = cy - markerH / 2;
        return (
          <g key={n} fill={color} opacity={dim ? 0.16 : 1}
            stroke={isMulti ? "#ffffff" : isSel ? P.text : "rgba(0,0,0,0.4)"}
            strokeWidth={isMulti ? sw * 0.004 : isSel ? sw * 0.0026 : sw * 0.0005}
            style={{ cursor: "crosshair" }}
            onClick={(e) => onClick(n, e.shiftKey)}
          >
            <title>{`${trackerId(subKey, n)}  •  Grupo ${g}\nLavagem: ${LAYERS[0].states[st[0]]}\nRoçagem: ${LAYERS[1].states[st[1]]}\nTrator: ${LAYERS[2].states[st[2]]}`}</title>
            <rect x={left} y={top} width={railW} height={markerH} rx={railW * 0.35} />
            <rect x={left + markerW - railW} y={top} width={railW} height={markerH} rx={railW * 0.35} />
            <rect x={left} y={cy - hubH / 2} width={markerW} height={hubH} rx={hubH * 0.3} />
          </g>
        );
      })}

      {dragRect && (() => {
        const rx = Math.min(dragRect.x1, dragRect.x2), ry = Math.min(dragRect.y1, dragRect.y2);
        const rw = Math.abs(dragRect.x2 - dragRect.x1), rh = Math.abs(dragRect.y2 - dragRect.y1);
        const dsw = sw * 0.0012;
        return <rect x={rx} y={ry} width={rw} height={rh}
          fill="rgba(255,255,255,0.06)" stroke="rgba(255,255,255,0.55)"
          strokeWidth={dsw} strokeDasharray={`${dsw * 4} ${dsw * 2}`}
          style={{ pointerEvents: "none" }} />;
      })()}
    </svg>
  );
}

/* ════════════════════════════════════════════════════════════════════════
   PAINEL DE GRUPOS
   ════════════════════════════════════════════════════════════════════════ */
function GroupPanel({ geo, subKey, statuses, activeLayer, onBulk }) {
  const colors = STATE_COLORS[activeLayer];
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 7, maxHeight: 260, overflowY: "auto", paddingRight: 4 }}>
      {geo.groups.map((g) => {
        const stat = countDone(statuses, subKey, g.trackers, activeLayer);
        const complete = stat.done === stat.total;
        return (
          <div key={g.g} style={{
            display: "flex", alignItems: "center", gap: 8, background: P.card2,
            border: `1px solid ${P.border}`, borderRadius: 8, padding: "7px 10px",
          }}>
            <span style={{ fontFamily: "monospace", fontSize: 12, color: P.text, fontWeight: 700, width: 26 }}>G{g.g}</span>
            <div style={{ flex: 1 }}>
              <ProgressBar done={stat.done} prog={stat.prog} total={stat.total} color={colors[LAYER_DONE_IDX[activeLayer]]} />
            </div>
            <span style={{ fontSize: 10.5, color: P.muted, fontFamily: "monospace", width: 42, textAlign: "right" }}>{stat.done}/{stat.total}</span>
            <button onClick={() => onBulk(g.trackers.map((t) => t[0]), complete ? 0 : 2)} title={complete ? "Resetar grupo" : "Concluir grupo"} style={{
              background: complete ? P.danger + "18" : P.accentG, border: `1px solid ${complete ? P.danger + "55" : P.accent + "55"}`,
              color: complete ? P.danger : P.accent, borderRadius: 6, padding: "4px 8px", fontSize: 11, cursor: "pointer", fontFamily: "inherit", fontWeight: 600,
            }}>{complete ? "↺" : "✓"}</button>
          </div>
        );
      })}
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════════════
   FERRAMENTA DE INTERVALO (1 a 132)
   ════════════════════════════════════════════════════════════════════════ */
function RangeTool({ activeLayer, onApply }) {
  const layer = LAYERS.find((l) => l.key === activeLayer);
  const [from, setFrom] = useState(1);
  const [to, setTo] = useState(132);
  const [val, setVal] = useState(2);
  return (
    <div style={{ display: "flex", gap: 8, alignItems: "center", flexWrap: "wrap" }}>
      <span style={{ fontSize: 11.5, color: P.muted }}>Tracker</span>
      <input type="number" min={1} max={132} value={from} onChange={(e) => setFrom(+e.target.value)}
        style={{ width: 56, background: P.bg, border: `1px solid ${P.border}`, borderRadius: 6, color: P.text, padding: "5px 6px", fontFamily: "monospace", fontSize: 12 }} />
      <span style={{ color: P.muted, fontSize: 11.5 }}>até</span>
      <input type="number" min={1} max={132} value={to} onChange={(e) => setTo(+e.target.value)}
        style={{ width: 56, background: P.bg, border: `1px solid ${P.border}`, borderRadius: 6, color: P.text, padding: "5px 6px", fontFamily: "monospace", fontSize: 12 }} />
      <select value={val} onChange={(e) => setVal(+e.target.value)} style={{
        background: P.bg, border: `1px solid ${P.border}`, borderRadius: 6, color: P.text, padding: "5px 6px", fontSize: 12, fontFamily: "inherit",
      }}>
        {layer.states.map((s, i) => <option key={i} value={i}>{s}</option>)}
      </select>
      <button onClick={() => onApply(from, to, val)} style={{
        background: P.accentG, border: `1px solid ${P.accent}66`, color: P.accent, borderRadius: 6,
        padding: "6px 14px", fontSize: 12, fontWeight: 700, cursor: "pointer", fontFamily: "inherit",
      }}>Aplicar</button>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════════════
   VISÃO DE UM SUBCAMPO
   ════════════════════════════════════════════════════════════════════════ */
function SubcampoView({ subKey, statuses, setStatuses, activeLayer, setActiveLayer, onNavigate }) {
  const geo = useSubGeometry(subKey);
  const [filter, setFilter] = useState(null);
  const [showGroups, setShowGroups] = useState(true);
  const [selected, setSelected] = useState(null);
  const [lastClicked, setLastClicked] = useState(null);
  const [scale, setScale] = useState(1);
  const [multiSelected, setMultiSelected] = useState([]);
  const [dragRect, setDragRect] = useState(null);
  const containerRef = useRef(null);
  const dragRef = useRef({ active: false, moved: false });
  const wasDragRef = useRef(false);

  const applyToTrackers = useCallback((ns, value) => {
    setStatuses((prev) => {
      const next = { ...prev, [subKey]: { ...(prev[subKey] || {}) } };
      ns.forEach((n) => {
        const cur = next[subKey][n] || [0, 0, 0];
        const updated = [...cur];
        updated[LAYER_IDX[activeLayer]] = value;
        if (updated[0] === 0 && updated[1] === 0 && updated[2] === 0) delete next[subKey][n];
        else next[subKey][n] = updated;
      });
      return next;
    });
  }, [subKey, activeLayer, setStatuses]);

  const pixelToSvg = useCallback((clientX, clientY) => {
    const el = containerRef.current;
    if (!el) return { x: 0, y: 0 };
    const r = el.getBoundingClientRect();
    const vW = geo.W / scale, vH = geo.H / scale;
    const vX = (geo.W - vW) / 2, vY = (geo.H - vH) / 2;
    return { x: vX + (clientX - r.left) / r.width * vW, y: vY + (clientY - r.top) / r.height * vH };
  }, [geo.W, geo.H, scale]);

  const handleSvgMouseDown = useCallback((e) => {
    if (e.button !== 0) return;
    const pos = pixelToSvg(e.clientX, e.clientY);
    dragRef.current = { active: true, x1px: e.clientX, y1px: e.clientY, x1: pos.x, y1: pos.y, x2: pos.x, y2: pos.y, moved: false };
  }, [pixelToSvg]);

  useEffect(() => {
    const onMove = (e) => {
      const dr = dragRef.current;
      if (!dr.active) return;
      const dx = e.clientX - dr.x1px, dy = e.clientY - dr.y1px;
      if (!dr.moved && Math.hypot(dx, dy) < 6) return;
      dr.moved = true;
      wasDragRef.current = true;
      const pos = pixelToSvg(e.clientX, e.clientY);
      dr.x2 = pos.x; dr.y2 = pos.y;
      setDragRect({ x1: dr.x1, y1: dr.y1, x2: dr.x2, y2: dr.y2 });
    };
    const onUp = () => {
      const dr = dragRef.current;
      if (!dr.active) return;
      dr.active = false;
      setDragRect(null);
      setTimeout(() => { wasDragRef.current = false; }, 50);
      if (!dr.moved) return;
      const rx1 = Math.min(dr.x1, dr.x2), rx2 = Math.max(dr.x1, dr.x2);
      const ry1 = Math.min(dr.y1, dr.y2), ry2 = Math.max(dr.y1, dr.y2);
      const { trackers, minX, maxY: gMaxY, pad, padTop, col, row } = geo;
      const mW = col * 0.82, mH = row * 0.5;
      const toX = (x) => x - minX + pad;
      const toY = (y) => gMaxY - y + padTop;
      const hits = trackers
        .filter(([, tx, ty]) => {
          const cx = toX(tx), cy = toY(ty);
          return cx - mW / 2 < rx2 && cx + mW / 2 > rx1 && cy - mH / 2 < ry2 && cy + mH / 2 > ry1;
        })
        .map(([n]) => n);
      setMultiSelected(hits);
    };
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
    return () => { window.removeEventListener("mousemove", onMove); window.removeEventListener("mouseup", onUp); };
  }, [pixelToSvg, geo]);

  useEffect(() => {
    const onKey = (e) => { if (e.key === "Escape") setMultiSelected([]); };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, []);

  const handleTrackerClick = useCallback((n, shiftKey) => {
    if (wasDragRef.current) return;
    setMultiSelected([]);
    const cur = getStatus(statuses, subKey, n)[LAYER_IDX[activeLayer]];
    const newVal = (cur + 1) % LAYERS.find((l) => l.key === activeLayer).states.length;
    if (shiftKey && lastClicked && lastClicked.subKey === subKey) {
      const lo = Math.min(lastClicked.n, n), hi = Math.max(lastClicked.n, n);
      const ns = [];
      for (let i = lo; i <= hi; i++) ns.push(i);
      applyToTrackers(ns, newVal);
    } else {
      applyToTrackers([n], newVal);
    }
    setSelected(n);
    setLastClicked({ subKey, n });
  }, [statuses, subKey, activeLayer, lastClicked, applyToTrackers]);

  const stat = countDone(statuses, subKey, geo.trackers, activeLayer);
  const colors = STATE_COLORS[activeLayer];
  const selStatus = selected != null ? getStatus(statuses, subKey, selected) : null;

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 10, height: "100%" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap", flexShrink: 0 }}>
        <button onClick={() => onNavigate(null)} style={{
          background: "none", border: `1px solid ${P.border}`, color: P.muted, borderRadius: 7,
          padding: "6px 12px", cursor: "pointer", fontSize: 12.5, fontFamily: "inherit",
        }}>← Visão geral</button>
        <h2 style={{ fontSize: 18, fontWeight: 700, color: P.text, margin: 0 }}>SDM {subKey}</h2>
        <select value={subKey} onChange={(e) => onNavigate(e.target.value)} style={{
          marginLeft: "auto", background: P.card, border: `1px solid ${P.border}`, color: P.text,
          borderRadius: 7, padding: "6px 10px", fontSize: 12.5, fontFamily: "inherit",
        }}>
          {SUB_KEYS.map((k) => <option key={k} value={k}>SDM {k}</option>)}
        </select>
      </div>

      <div style={{ display: "flex", gap: 14, flexWrap: "wrap", alignItems: "center", flexShrink: 0 }}>
        <LayerTabs active={activeLayer} onChange={setActiveLayer} />
        <div style={{ flex: 1, minWidth: 160 }}>
          <ProgressBar done={stat.done} prog={stat.prog} total={stat.total} color={colors[LAYER_DONE_IDX[activeLayer]]} />
        </div>
        <span style={{ fontFamily: "monospace", fontSize: 12, color: colors[LAYER_DONE_IDX[activeLayer]], fontWeight: 700 }}>✓ {stat.done}</span>
        {stat.prog > 0 && <span style={{ fontFamily: "monospace", fontSize: 12, color: P.warn, fontWeight: 700 }}>½ {stat.prog}</span>}
        <span style={{ fontFamily: "monospace", fontSize: 12, color: P.muted }}>/{stat.total}</span>
      </div>

      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 10, flexShrink: 0 }}>
        <FilterChips activeLayer={activeLayer} filter={filter} onChange={setFilter} />
        <label style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 12, color: P.muted, cursor: "pointer" }}>
          <input type="checkbox" checked={showGroups} onChange={(e) => setShowGroups(e.target.checked)} />
          Contornos de grupo
        </label>
      </div>

      <div style={{ display: "flex", gap: 14, flex: 1, minHeight: 0 }}>
        <div ref={containerRef} style={{
          flex: "2 1 420px", background: P.surface, border: `1px solid ${P.border}`, borderRadius: 12,
          padding: 12, overflow: "hidden", position: "relative",
        }}>
          <div style={{ position: "absolute", top: 10, right: 10, zIndex: 2, display: "flex", gap: 6 }}>
            <button onClick={() => setScale((s) => Math.min(8, s * 1.25))} style={zoomBtnStyle}>＋</button>
            <button onClick={() => setScale((s) => Math.max(1, s / 1.25))} style={zoomBtnStyle}>－</button>
          </div>
          <SubMap geo={geo} subKey={subKey} statuses={statuses} activeLayer={activeLayer}
            filter={filter} showGroups={showGroups} selected={selected}
            multiSelected={multiSelected} dragRect={dragRect} onSvgMouseDown={handleSvgMouseDown}
            onClick={handleTrackerClick} scale={scale} />
          {multiSelected.length > 0 && (
            <div style={{
              position: "absolute", bottom: 14, left: "50%", transform: "translateX(-50%)",
              background: P.card, border: `1px solid ${P.border}`, borderRadius: 10,
              padding: "8px 12px", display: "flex", gap: 6, alignItems: "center",
              zIndex: 10, boxShadow: "0 4px 24px #0009", whiteSpace: "nowrap",
            }}>
              <span style={{ color: P.muted, fontSize: 11.5, fontFamily: "monospace", marginRight: 4 }}>
                {multiSelected.length} trackers:
              </span>
              {LAYERS.find((l) => l.key === activeLayer).states.map((s, i) => (
                <button key={i} onClick={() => { applyToTrackers(multiSelected, i); setMultiSelected([]); }} style={{
                  background: STATE_COLORS[activeLayer][i] + "28",
                  border: `1px solid ${STATE_COLORS[activeLayer][i]}66`,
                  color: P.text, borderRadius: 6, padding: "4px 9px", fontSize: 11, cursor: "pointer", fontFamily: "inherit",
                }}>{s}</button>
              ))}
              <button onClick={() => setMultiSelected([])} style={{
                background: "none", border: "none", color: P.muted, cursor: "pointer", fontSize: 15, lineHeight: 1, padding: "0 2px",
              }}>✕</button>
            </div>
          )}
        </div>

        <div style={{ flex: "1 1 260px", display: "flex", flexDirection: "column", gap: 12, overflowY: "auto" }}>
          <div style={{ background: P.card, border: `1px solid ${P.border}`, borderRadius: 12, padding: 14 }}>
            <div style={{ color: P.muted, fontSize: 11, fontFamily: "monospace", marginBottom: 8, letterSpacing: 0.5 }}>TRACKER SELECIONADO</div>
            {selected != null ? (
              <div>
                <div style={{ color: P.text, fontWeight: 700, fontSize: 14, marginBottom: 8, fontFamily: "monospace" }}>{trackerId(subKey, selected)}</div>
                {LAYERS.map((l, i) => (
                  <div key={l.key} style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
                    <span style={{ fontSize: 11.5, color: P.muted, width: 92 }}>{l.icon} {l.label}</span>
                    <button onClick={() => applyToTrackers([selected], (selStatus[i] + 1) % LAYERS[i].states.length)} style={{
                      background: STATE_COLORS[l.key][selStatus[i]] + "33", border: `1px solid ${STATE_COLORS[l.key][selStatus[i]]}77`,
                      color: P.text, borderRadius: 6, padding: "4px 9px", fontSize: 11.5, cursor: "pointer", fontFamily: "inherit",
                    }}>{l.states[selStatus[i]]}</button>
                  </div>
                ))}
              </div>
            ) : <div style={{ color: P.muted, fontSize: 12.5 }}>Toque em um tracker no mapa para ver e editar o status. Shift+clique pinta um intervalo.</div>}
          </div>

          <div style={{ background: P.card, border: `1px solid ${P.border}`, borderRadius: 12, padding: 14 }}>
            <div style={{ color: P.muted, fontSize: 11, fontFamily: "monospace", marginBottom: 10, letterSpacing: 0.5 }}>MARCAR INTERVALO (1–132)</div>
            <RangeTool activeLayer={activeLayer} onApply={(from, to, val) => {
              const lo = Math.max(1, Math.min(from, to)), hi = Math.min(132, Math.max(from, to));
              const ns = []; for (let i = lo; i <= hi; i++) ns.push(i);
              applyToTrackers(ns, val);
            }} />
          </div>

          <div style={{ background: P.card, border: `1px solid ${P.border}`, borderRadius: 12, padding: 14 }}>
            <div style={{ color: P.muted, fontSize: 11, fontFamily: "monospace", marginBottom: 10, letterSpacing: 0.5 }}>GRUPOS DE COMANDO</div>
            <GroupPanel geo={geo} subKey={subKey} statuses={statuses} activeLayer={activeLayer}
              onBulk={(ns, val) => applyToTrackers(ns, val)} />
          </div>

          <Legend activeLayer={activeLayer} />
        </div>
      </div>
    </div>
  );
}

const zoomBtnStyle = {
  width: 26, height: 26, borderRadius: 6, border: `1px solid ${P.border}`, background: P.card,
  color: P.text, cursor: "pointer", fontSize: 14, fontFamily: "inherit", lineHeight: 1,
};

/* ════════════════════════════════════════════════════════════════════════
   VISÃO GERAL — mapa geral de toda a usina, posições reais
   ════════════════════════════════════════════════════════════════════════ */
function OverviewMap({ statuses, activeLayer, onSelect }) {
  const containerRef = useRef(null);
  const [zoom, setZoom] = useState(1);
  const [offset, setOffset] = useState({ x: 0, y: 0 });
  const dragRef = useRef(null);

  const { all, minX, maxX, minY, maxY } = useMemo(() => {
    let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
    const all = [];
    SUB_KEYS.forEach((key) => {
      PLANT[key].t.forEach(([n, x, y, g]) => {
        all.push({ key, n, x, y, g });
        if (x < minX) minX = x; if (x > maxX) maxX = x;
        if (y < minY) minY = y; if (y > maxY) maxY = y;
      });
    });
    return { all, minX, maxX, minY, maxY };
  }, []);

  const idx = LAYER_IDX[activeLayer];
  const pad = 30, padTop = 55;
  const W = maxX - minX + pad * 2, H = maxY - minY + pad + padTop;
  const toX = (x) => x - minX + pad;
  const toY = (y) => maxY - y + padTop;
  const markerW = 9, markerH = 22;

  const subBoxes = useMemo(() => SUB_KEYS.map((key) => {
    const pts = PLANT[key].t;
    const xs = pts.map((p) => p[1]), ys = pts.map((p) => p[2]);
    return { key, minX: Math.min(...xs), maxX: Math.max(...xs), minY: Math.min(...ys), maxY: Math.max(...ys) };
  }), []);

  const clampOffset = useCallback((ox, oy, z) => {
    const vW = W / z, vH = H / z;
    const maxOx = (W - vW) / 2, maxOy = (H - vH) / 2;
    return { x: Math.max(-maxOx, Math.min(maxOx, ox)), y: Math.max(-maxOy, Math.min(maxOy, oy)) };
  }, [W, H]);

  const handleWheel = useCallback((e) => {
    e.preventDefault();
    const el = containerRef.current;
    if (!el) return;
    const rect = el.getBoundingClientRect();
    const mx = (e.clientX - rect.left) / rect.width;
    const my = (e.clientY - rect.top) / rect.height;
    setZoom((z) => {
      const newZ = Math.max(1, Math.min(10, z * (e.deltaY < 0 ? 1.15 : 1 / 1.15)));
      const vW = W / z, vH = H / z;
      const nvW = W / newZ, nvH = H / newZ;
      setOffset((o) => clampOffset(
        o.x + (nvW - vW) * (0.5 - mx),
        o.y + (nvH - vH) * (0.5 - my),
        newZ,
      ));
      return newZ;
    });
  }, [W, H, clampOffset]);

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    el.addEventListener("wheel", handleWheel, { passive: false });
    return () => el.removeEventListener("wheel", handleWheel);
  }, [handleWheel]);

  const handleMouseDown = useCallback((e) => {
    if (zoom <= 1) return;
    e.preventDefault();
    dragRef.current = { startX: e.clientX, startY: e.clientY, ox: offset.x, oy: offset.y };
  }, [zoom, offset]);

  const handleMouseMove = useCallback((e) => {
    if (!dragRef.current) return;
    const el = containerRef.current;
    if (!el) return;
    const rect = el.getBoundingClientRect();
    const vW = W / zoom, vH = H / zoom;
    const dx = (e.clientX - dragRef.current.startX) / rect.width * vW;
    const dy = (e.clientY - dragRef.current.startY) / rect.height * vH;
    setOffset(clampOffset(dragRef.current.ox - dx, dragRef.current.oy - dy, zoom));
  }, [zoom, W, H, clampOffset]);

  const handleMouseUp = useCallback(() => { dragRef.current = null; }, []);

  useEffect(() => {
    window.addEventListener("mousemove", handleMouseMove);
    window.addEventListener("mouseup", handleMouseUp);
    return () => {
      window.removeEventListener("mousemove", handleMouseMove);
      window.removeEventListener("mouseup", handleMouseUp);
    };
  }, [handleMouseMove, handleMouseUp]);

  const vW = W / zoom, vH = H / zoom;
  const vX = (W - vW) / 2 + offset.x, vY = (H - vH) / 2 + offset.y;

  return (
    <div ref={containerRef} onMouseDown={handleMouseDown} style={{
      flex: 1, minHeight: 0,
      background: P.surface, border: `1px solid ${P.border}`, borderRadius: 12, padding: 12,
      overflow: "hidden", cursor: zoom > 1 ? (dragRef.current ? "grabbing" : "grab") : "default",
      userSelect: "none",
    }}>
      <svg width="100%" height="100%" viewBox={`${vX} ${vY} ${vW} ${vH}`} preserveAspectRatio="xMidYMid meet" style={{ display: "block" }}>
        {subBoxes.map((b) => {
          const stat = countDone(statuses, b.key, PLANT[b.key].t, activeLayer);
          const pct = stat.total ? stat.done / stat.total : 0;
          const bx = toX(b.minX) - 14, by = toY(b.maxY) - 14;
          const bw = (b.maxX - b.minX) + 28, bh = (b.maxY - b.minY) + 28;
          return (
            <g key={b.key} style={{ cursor: "pointer" }} onClick={() => onSelect(b.key)}>
              <rect x={bx} y={by} width={bw} height={bh} rx={10}
                fill={P.card} stroke={pct === 1 ? P.accent : P.border} strokeWidth={2} opacity={0.9} />
              <rect x={bx} y={by - 38} width={bw} height={34} rx={8}
                fill={P.bg} stroke={pct === 1 ? P.accent : P.border} strokeWidth={1.5} opacity={0.95} />
              <text x={bx + 10} y={by - 22} fontSize={14} fill={P.text} fontFamily="monospace" fontWeight="700">SDM {b.key}</text>
              <text x={bx + 10} y={by - 8} fontSize={11} fill={pct === 1 ? P.accent : P.muted} fontFamily="monospace">{stat.done}/{stat.total} · {Math.round(pct * 100)}%</text>
            </g>
          );
        })}
        {all.map((p) => {
          const val = getStatus(statuses, p.key, p.n)[idx];
          const color = STATE_COLORS[activeLayer][val];
          return (
            <rect key={p.key + "-" + p.n}
              x={toX(p.x) - markerW / 2} y={toY(p.y) - markerH / 2}
              width={markerW} height={markerH} rx={2}
              fill={color} opacity={0.95} style={{ pointerEvents: "none" }} />
          );
        })}
      </svg>
    </div>
  );
}

function OverviewCards({ statuses, activeLayer, onSelect }) {
  return (
    <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(150px,1fr))", gap: 10 }}>
      {SUB_KEYS.map((key) => {
        const stat = countDone(statuses, key, PLANT[key].t, activeLayer);
        const pct = stat.total ? Math.round((stat.done / stat.total) * 100) : 0;
        const colors = STATE_COLORS[activeLayer];
        return (
          <button key={key} onClick={() => onSelect(key)} style={{
            textAlign: "left", background: P.card, border: `1px solid ${pct === 100 ? P.accent + "77" : P.border}`,
            borderRadius: 10, padding: "12px 14px", cursor: "pointer", fontFamily: "inherit",
          }}>
            <div style={{ color: P.text, fontWeight: 700, fontSize: 14, marginBottom: 6 }}>SDM {key}</div>
            <ProgressBar done={stat.done} prog={stat.prog} total={stat.total} color={colors[LAYER_DONE_IDX[activeLayer]]} />
            <div style={{ color: P.muted, fontSize: 11, fontFamily: "monospace", marginTop: 6 }}>{stat.done}/{stat.total} · {pct}%</div>
          </button>
        );
      })}
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════════════
   APP
   ════════════════════════════════════════════════════════════════════════ */
const STORAGE_ROW_ID = "sdm_tracker_status_v1";

export default function App() {
  const [view, setView] = useState("overview");
  const [activeLayer, setActiveLayer] = useState("lavagem");
  const [statuses, setStatuses] = useState({});
  const [loaded, setLoaded] = useState(false);
  const [syncState, setSyncState] = useState("loading"); // loading | ok | saving | error | offline
  const saveTimer = useRef(null);
  const skipNextRealtime = useRef(false);
  const userDirty = useRef(false);

  const setStatusesByUser = useCallback((updater) => {
    userDirty.current = true;
    setStatuses(updater);
  }, []);

  useEffect(() => {
    let channel;
    (async () => {
      if (!supabase) {
        setSyncState("offline");
        setLoaded(true);
        return;
      }
      try {
        const { data, error } = await supabase
          .from("tracker_status")
          .select("value")
          .eq("id", STORAGE_ROW_ID)
          .maybeSingle();
        if (error) throw error;
        if (data && data.value) setStatuses(data.value);
        setSyncState("ok");
      } catch (e) {
        console.error("Erro ao carregar do Supabase:", e);
        setSyncState("error");
      }
      setLoaded(true);

      channel = supabase
        .channel("tracker_status_changes")
        .on(
          "postgres_changes",
          { event: "*", schema: "public", table: "tracker_status", filter: `id=eq.${STORAGE_ROW_ID}` },
          (payload) => {
            if (skipNextRealtime.current) { skipNextRealtime.current = false; return; }
            if (userDirty.current) return;
            if (payload.new && payload.new.value) setStatuses(payload.new.value);
          }
        )
        .subscribe();
    })();
    return () => { if (channel && supabase) supabase.removeChannel(channel); };
  }, []);

  useEffect(() => {
    if (!loaded || !supabase || !userDirty.current) return;
    if (saveTimer.current) clearTimeout(saveTimer.current);
    saveTimer.current = setTimeout(async () => {
      userDirty.current = false;
      setSyncState("saving");
      try {
        skipNextRealtime.current = true;
        const { error } = await supabase
          .from("tracker_status")
          .upsert({ id: STORAGE_ROW_ID, value: statuses, updated_at: new Date().toISOString() });
        if (error) throw error;
        setSyncState("ok");
      } catch (e) {
        userDirty.current = true;
        console.error("Erro ao salvar no Supabase:", e);
        setSyncState("error");
      }
    }, 800);
  }, [statuses, loaded]);

  const globalStat = useMemo(() => {
    const allPoints = SUB_KEYS.flatMap((k) => PLANT[k].t.map((t) => ({ key: k, n: t[0] })));
    const idx = LAYER_IDX[activeLayer];
    let done = 0, prog = 0;
    const layer = LAYERS.find((l) => l.key === activeLayer);
    allPoints.forEach((p) => {
      const v = getStatus(statuses, p.key, p.n)[idx];
      if (v === layer.doneIdx) done++;
      else if (layer.progIdxes.includes(v)) prog++;
    });
    return { done, prog, total: allPoints.length };
  }, [statuses, activeLayer]);

  return (
    <div style={{
      height: "100vh", background: P.bg, color: P.text,
      fontFamily: "'IBM Plex Sans','Segoe UI',sans-serif", padding: "12px 16px",
      display: "flex", flexDirection: "column", overflow: "hidden",
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@400;600;700&family=IBM+Plex+Mono:wght@500;700&display=swap');
        *{box-sizing:border-box}
        code,.mono{font-family:'IBM Plex Mono',monospace}
        @keyframes pulse{0%,100%{opacity:1}50%{opacity:.25}}
        ::-webkit-scrollbar{width:7px;height:7px}::-webkit-scrollbar-track{background:${P.surface}}::-webkit-scrollbar-thumb{background:${P.border};border-radius:4px}
        select, input, button { font-family: inherit; }
        button:hover { filter: brightness(1.12); }
        html, body { margin: 0; padding: 0; height: 100%; overflow: hidden; }
      `}</style>

      <div style={{ display: "flex", flexDirection: "column", flex: 1, minHeight: 0 }}>
        <div style={{ marginBottom: 8, flexShrink: 0 }}>
          <div style={{ display: "inline-flex", alignItems: "center", gap: 8, background: P.accentG,
            border: `1px solid ${P.accent}33`, borderRadius: 6, padding: "4px 14px" }}>
            <span style={{ color: P.accent, fontSize: 11, fontFamily: "monospace", letterSpacing: 1 }}>UFV SDM · STATUS DE CAMPO</span>
            <SyncBadge state={syncState} />
          </div>
        </div>

        {!loaded ? (
          <div style={{ color: P.muted, fontSize: 13 }}>Carregando status salvo...</div>
        ) : view === "overview" ? (
          <div style={{ display: "flex", flexDirection: "column", gap: 8, flex: 1, minHeight: 0 }}>
            <div style={{ display: "flex", gap: 14, flexWrap: "wrap", alignItems: "center", flexShrink: 0 }}>
              <LayerTabs active={activeLayer} onChange={setActiveLayer} />
              <div style={{ flex: 1, minWidth: 160 }}>
                <ProgressBar done={globalStat.done} prog={globalStat.prog} total={globalStat.total} color={STATE_COLORS[activeLayer][LAYER_DONE_IDX[activeLayer]]} />
              </div>
              <span style={{ fontFamily: "monospace", fontSize: 12, color: STATE_COLORS[activeLayer][LAYER_DONE_IDX[activeLayer]], fontWeight: 700 }}>
                ✓ {globalStat.done}
              </span>
              {globalStat.prog > 0 && (
                <span style={{ fontFamily: "monospace", fontSize: 12, color: P.warn, fontWeight: 700 }}>
                  ½ {globalStat.prog}
                </span>
              )}
              <span style={{ fontFamily: "monospace", fontSize: 12, color: P.muted }}>
                /{globalStat.total} trackers
              </span>
            </div>
            <Legend activeLayer={activeLayer} />
            <OverviewMap statuses={statuses} activeLayer={activeLayer} onSelect={setView} />
          </div>
        ) : (
          <div style={{ flex: 1, minHeight: 0 }}>
            <SubcampoView key={view} subKey={view} statuses={statuses} setStatuses={setStatusesByUser}
              activeLayer={activeLayer} setActiveLayer={setActiveLayer}
              onNavigate={(key) => setView(key || "overview")} />
          </div>
        )}
      </div>
    </div>
  );
}
